219→export function createInitialEditorState(activeFloorId = null) {
220→  const modelViewport = getInitialModelViewport();
221→  const sheetViewport = getInitialSheetViewport();
222→  return {
223→    activeTool: TOOLS.SELECT,
224→    modelTarget: 'floor',
225→    selectedId: null,
226→    selectedType: null,
227→    toolState: {},
228→    workspaceMode: 'model',
229→    viewport: { ...modelViewport },
230→    modelViewport,
231→    sheetViewport,
232→    showGrid: true,
233→    snapEnabled: true,
234→    viewMode: 'plan',
235→    activeFloorId,
236→    activeSheetId: null,
237→    activeSectionCutId: null,
238→    statusMessage: null,
239→    regionSelection: null,
240→    pastePreview: { active: false, point: null },
241→    maximizedPanel: null,
242→    activePhaseId: null,
243→    phaseViewMode: 'all',
244→  };
245→}
246→
247→export function EditorProvider({ children, initialActiveFloorId = null, availableFloorIds = [], availablePhaseIds = [] }) {
248→  const [state, dispatch] = useReducer(
249→    editorReducer,
250→    initialActiveFloorId,
251→    createInitialEditorState
252→  );
253→
254→  useEffect(() => {
255→    if (!availableFloorIds.length) {
256→      if (state.activeFloorId !== null) {
257→        dispatch({ type: 'SET_ACTIVE_FLOOR', floorId: null });
258→      }
259→      return;
260→    }
261→
262→    if (!state.activeFloorId || !availableFloorIds.includes(state.activeFloorId)) {
263→      dispatch({ type: 'SET_ACTIVE_FLOOR', floorId: availableFloorIds[0] });
264→    }
265→  }, [availableFloorIds, state.activeFloorId]);
266→
267→  useEffect(() => {
268→    if (state.activePhaseId && !availablePhaseIds.includes(state.activePhaseId)) {
269→      dispatch({ type: 'SET_ACTIVE_PHASE', phaseId: null });
270→      dispatch({ type: 'SET_PHASE_VIEW_MODE', mode: 'all' });
271→    }
272→  }, [availablePhaseIds, state.activePhaseId]);
273→
274→  return (
275→    <EditorContext.Provider value={{ state, dispatch }}>
276→      {children}
277→    </EditorContext.Provider>
278→  );
279→}
280→
281→export function useEditor() {
282→  const ctx = useContext(EditorContext);
283→  if (!ctx) throw new Error('useEditor must be used within EditorProvider');
284→  return { ...ctx.state, dispatch: ctx.dispatch };
285→}
