  1→import { lazy, Suspense, useState, useEffect, useCallback, useMemo, useRef } from 'react';
  2→import { ProjectProvider, useProject } from '@/app/ProjectProvider';
  3→import { EditorProvider, useEditor } from '@/app/EditorProvider';
  4→import { ClipboardProvider } from '@/app/ClipboardProvider';
  5→import SvgCanvas from '@/renderers/SvgCanvas';
  6→import SheetCanvas from '@/renderers/SheetCanvas';
  7→import Toolbar from '@/ui/Toolbar';
  8→import Sidebar from '@/ui/Sidebar';
  9→import PropertiesPanel from '@/ui/PropertiesPanel';
 10→import Modal from '@/ui/Modal';
 11→import NewProjectModal from '@/ui/NewProjectModal';
 12→import { createProject } from '@/domain/models';
 13→import { getDefaultActiveFloorId, getOrderedFloors } from '@/domain/floorModels';
 14→import { saveProject, loadProject, listProjects, deleteProject } from '@/persistence/storage';
 15→import {
 16→  exportProjectFile,
 17→  importProjectFile,
 18→  isFilePickerAbortError,
 19→  openProjectFile,
 20→} from '@/persistence/fileTransfer';
 21→import { useAutosave } from '@/persistence/useAutosave';
 22→import { isTypingTarget } from '@/utils/keyboard';
 23→import styles from '@/app/App.module.css';
 24→import modalStyles from '@/ui/Modal.module.css';
 25→
 26→const ThreePreviewPanel = lazy(() => import('@/three/viewer/ThreePreviewPanel'));
 27→
 28→function EditorShell({
 29→  project,
 30→  handleNew,
 31→  handleSave,
 32→  handleLoadClick,
 33→  isSidebarCollapsed,
 34→  isPropertiesCollapsed,
 35→  onToggleSidebar,
 36→  onToggleProperties,
 37→}) {
 38→  const {
 39→    workspaceMode,
 40→    activeSheetId,
 41→    activeFloorId,
 42→    maximizedPanel,
 43→    dispatch: editorDispatch,
 44→  } = useEditor();
 45→
 46→  useEffect(() => {
 47→    const sheets = project.sheets || [];
 48→    if (!sheets.length) {
 49→      if (activeSheetId !== null) {
 50→        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: null });
 51→      }
 52→      if (workspaceMode === 'sheet') {
 53→        editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
 54→      }
 55→      return;
 56→    }
 57→
 58→    if (!activeSheetId || !sheets.some((sheet) => sheet.id === activeSheetId)) {
 59→      editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheets[0].id });
 60→    }
 61→  }, [activeSheetId, editorDispatch, project.sheets, workspaceMode]);
 62→
 63→  return (
 64→    <div
 65→      className={styles.layout}
 66→      style={{
 67→        '--layout-sidebar-width': isSidebarCollapsed ? '0px' : 'var(--sidebar-width)',
 68→        '--layout-properties-width': isPropertiesCollapsed ? '0px' : 'var(--properties-width)',
 69→      }}
 70→    >
 71→      <div className={styles.toolbar}>
 72→        <Toolbar
 73→          onNew={handleNew}
 74→          onSave={handleSave}
 75→          onLoad={handleLoadClick}
 76→          isSidebarCollapsed={isSidebarCollapsed}
 77→          isPropertiesCollapsed={isPropertiesCollapsed}
 78→          onToggleSidebar={onToggleSidebar}
 79→          onToggleProperties={onToggleProperties}
 80→        />
 81→      </div>
 82→      <div className={`${styles.sidebar} ${isSidebarCollapsed ? styles.panelHidden : styles.sidebarVisible}`}>
 83→        <Sidebar />
 84→      </div>
 85→      <div className={styles.canvas}>
 86→        {workspaceMode === 'sheet' ? (
 87→          <SheetCanvas />
 88→        ) : (
 89→          <div className={`${styles.modelWorkspace} ${maximizedPanel ? styles.workspaceMaximized : ''}`}>
 90→            {maximizedPanel !== 'preview' && (
 91→              <div className={styles.primaryCanvas}>
 92→                <SvgCanvas />
 93→              </div>
 94→            )}
 95→            {maximizedPanel !== 'canvas' && (
 96→              <div className={styles.preview}>
 97→                <Suspense fallback={<div className={styles.previewFallback}>Loading 3D preview...</div>}>
 98→                  <ThreePreviewPanel
 99→                    project={project}
100→                    activeFloorId={activeFloorId}
101→                    isMaximized={maximizedPanel === 'preview'}
102→                    onToggleMaximize={() => editorDispatch({ type: 'TOGGLE_MAXIMIZE_PANEL', panel: 'preview' })}
103→                  />
104→                </Suspense>
105→              </div>
106→            )}
107→          </div>
108→        )}
109→      </div>
110→      <div className={`${styles.properties} ${isPropertiesCollapsed ? styles.panelHidden : styles.propertiesVisible}`}>
111→        <PropertiesPanel />
112→      </div>
113→    </div>
114→  );
115→}
