 112→async function preloadSvgImages(svgElement) {
 113→  const imageMap = new Map();
 114→  const imageElements = svgElement.querySelectorAll('image');
 115→  for (const el of imageElements) {
 116→    const href = el.getAttribute('href') || el.getAttributeNS('http://www.w3.org/1999/xlink', 'href');
 117→    if (!href || imageMap.has(href)) continue;
 118→    try {
 119→      const img = await loadImage(href);
 120→      const w = img.naturalWidth;
 121→      const h = img.naturalHeight;
 122→      const tempCanvas = document.createElement('canvas');
 123→      tempCanvas.width = w;
 124→      tempCanvas.height = h;
 125→      const ctx = tempCanvas.getContext('2d');
 126→      ctx.drawImage(img, 0, 0);
 127→      const jpegDataUrl = tempCanvas.toDataURL('image/jpeg', JPEG_QUALITY);
 128→      const base64 = jpegDataUrl.split(',')[1];
 129→      const binaryString = atob(base64);
 130→      const jpegBytes = new Uint8Array(binaryString.length);
 131→      for (let i = 0; i < binaryString.length; i++) {
 132→        jpegBytes[i] = binaryString.charCodeAt(i);
 133→      }
 134→      imageMap.set(href, { img, width: w, height: h, jpegBytes });
 135→    } catch {
 136→      // skip images that fail to load
 137→    }
 138→  }
 139→  return imageMap;
 140→}
