 198→        break;
 199→      case 'scale':
 200→        matrix = matrix.multiply(new DOMMatrix().scale(args[0] ?? 1, args[1] ?? args[0] ?? 1));
 201→        break;
 202→      case 'rotate':
 203→        if (args.length >= 3) {
 204→          matrix = matrix.multiply(new DOMMatrix().translate(args[1], args[2]).rotate(args[0]).translate(-args[1], -args[2]));
 205→        } else {
 206→          matrix = matrix.multiply(new DOMMatrix().rotate(args[0] || 0));
 207→        }
 208→        break;
 209→      case 'matrix':
 210→        if (args.length >= 6) {
 211→          matrix = matrix.multiply(new DOMMatrix([args[0], args[1], args[2], args[3], args[4], args[5]]));
 212→        }
