 921→function estimateTextWidth(text, fontSize) {
 922→  return text.length * fontSize * 0.56;
 923→}
 924→
 925→function renderTextLine(builder, text, x, y, style) {
 926→  if (!text) return;
 927→  let drawX = x;
 928→  const textWidth = estimateTextWidth(text, style.fontSize);
 929→  if (style.textAnchor === 'middle') drawX -= textWidth / 2;
 930→  else if (style.textAnchor === 'end') drawX -= textWidth;
 931→
 932→  let baselineY = y;
 933→  if (style.dominantBaseline === 'middle') {
 934→    baselineY += style.fontSize * 0.32;
 935→  }
 936→
 937→  builder.write('q');
 938→  builder.applyStyle(style, { fillAllowed: true, strokeAllowed: false });
 939→  builder.write('BT');
 940→  builder.write(`/F1 ${fmt(style.fontSize)} Tf`);
 941→  builder.write(`1 0 0 -1 ${fmt(drawX)} ${fmt(baselineY)} Tm`);
 942→  builder.write(`(${escapePdfText(text)}) Tj`);
 943→  builder.write('ET');
 944→  builder.write('Q');
 945→}
 946→
 947→function getTextLines(element) {
 948→  const x = Number(element.getAttribute('x')) || 0;
 949→  const y = Number(element.getAttribute('y')) || 0;
 950→  const tspans = [...element.children].filter((child) => child.tagName?.toLowerCase() === 'tspan');
 951→
 952→  if (!tspans.length) {
 953→    return [{ text: element.textContent || '', x, y }];
 954→  }
 955→
 956→  let currentY = y;
 957→  return tspans.map((tspan, index) => {
 958→    const text = tspan.textContent || '';
 959→    const lineX = tspan.hasAttribute('x') ? Number(tspan.getAttribute('x')) : x;
 960→    if (tspan.hasAttribute('y')) {
 961→      currentY = Number(tspan.getAttribute('y'));
 962→    } else if (tspan.hasAttribute('dy')) {
 963→      currentY += Number(tspan.getAttribute('dy'));
 964→    } else if (index > 0) {
 965→      currentY = y;
 966→    }
 967→    return { text, x: lineX, y: currentY };
 968→  });
 969→}
 970→
 971→function renderText(builder, element) {
 972→  const style = computeStyle(element);
 973→  if (!style.fill) return;
 974→  const lines = getTextLines(element);
 975→  lines.forEach((line) => renderTextLine(builder, line.text, line.x, line.y, style));
 976→}
 977→
 978→function renderImage(builder, element, imageMap) {
 979→  const href = element.getAttribute('href') || element.getAttributeNS('http://www.w3.org/1999/xlink', 'href');
 980→  const entry = href && imageMap.get(href);
 981→  if (!entry) return;
 982→  const x = Number(element.getAttribute('x')) || 0;
 983→  const y = Number(element.getAttribute('y')) || 0;
 984→  const width = Number(element.getAttribute('width')) || entry.width;
 985→  const height = Number(element.getAttribute('height')) || entry.height;
 986→  const imgName = builder.addImage(entry.jpegBytes, entry.width, entry.height);
 987→  builder.write('q');
 988→  builder.write(`${fmt(width)} 0 0 ${fmt(-height)} ${fmt(x)} ${fmt(y + height)} cm`);
 989→  builder.write(`/${imgName} Do`);
 990→  builder.write('Q');
 991→}
 992→
 993→function walkElement(builder, element, imageMap) {
 994→  const tagName = element.tagName.toLowerCase();
 995→  const wrapped = beginNode(builder, element);
 996→
 997→  switch (tagName) {
 998→    case 'svg':
 999→    case 'g':
1000→      [...element.children].forEach((child) => walkElement(builder, child, imageMap));
1001→      break;
1002→    case 'rect':
1003→      renderRect(builder, element);
1004→      break;
1005→    case 'line':
1006→      renderLine(builder, element);
1007→      break;
1008→    case 'polygon':
1009→      renderPolygonLike(builder, element, true);
1010→      break;
1011→    case 'polyline':
1012→      renderPolygonLike(builder, element, false);
1013→      break;
1014→    case 'path':
1015→      renderPath(builder, element);
1016→      break;
1017→    case 'text':
1018→      renderText(builder, element);
1019→      break;
1020→    case 'image':
1021→      renderImage(builder, element, imageMap);
1022→      break;
1023→    default:
1024→      [...element.children].forEach((child) => walkElement(builder, child, imageMap));
1025→      break;
1026→  }
1027→
1028→  endNode(builder, wrapped);
1029→}
