1045→export async function exportActiveSheetAsPng(sheetTitle = 'sheet', options = {}) {
1046→  const svgElement = getExportSvg();
1047→  if (!svgElement) throw new Error('No sheet export source is available.');
1048→  const { dpi = DEFAULT_PNG_DPI } = options;
1049→  const imageMap = await preloadSvgImages(svgElement);
1050→  const { canvas } = await renderSvgToCanvas(svgElement, dpi, imageMap);
1051→
1052→  await new Promise((resolve, reject) => {
1053→    canvas.toBlob((blob) => {
1054→      if (!blob) {
1055→        reject(new Error('Failed to render PNG export.'));
1056→        return;
1057→      }
1058→      downloadBlob(blob, `${sanitizeFileName(sheetTitle)}.png`);
1059→      resolve();
1060→    }, 'image/png');
1061→  });
1062→}
