1064→export async function exportActiveSheetAsPdf(sheetTitle = 'sheet', paperSize = 'A3_LANDSCAPE') {
1065→  const svgElement = getExportSvg();
1066→  if (!svgElement) throw new Error('No sheet export source is available.');
1067→  const imageMap = await preloadSvgImages(svgElement);
1068→  const pdfBlob = buildVectorPdfFromSvg(svgElement, paperSize, imageMap);
1069→  downloadBlob(pdfBlob, `${sanitizeFileName(sheetTitle)}.pdf`);
1070→}
