 27→function boundsFromPoints(points = [], fallback = { minX: -1000, maxX: 1000, minY: -1000, maxY: 1000 }) {
 28→  if (!points.length) return fallback;
 29→  return {
 30→    minX: Math.min(...points.map((point) => point.x)),
 31→    maxX: Math.max(...points.map((point) => point.x)),
 32→    minY: Math.min(...points.map((point) => point.y)),
 33→    maxY: Math.max(...points.map((point) => point.y)),
 34→  };
 35→}
 36→
 37→function expandBounds(bounds, paddingX, paddingY = paddingX) {
 38→  return {
 39→    minX: bounds.minX - paddingX,
 40→    maxX: bounds.maxX + paddingX,
 41→    minY: bounds.minY - paddingY,
 42→    maxY: bounds.maxY + paddingY,
 43→  };
 44→}
