 46→function collectPlanPoints(floor) {
 47→  const points = [];
 48→
 49→  for (const wall of floor.walls || []) {
 50→    points.push(...(getWallRenderData(wall, floor.columns || []).outline || []));
 51→  }
 52→  for (const room of floor.rooms || []) {
 53→    points.push(...(room.points || []));
 54→  }
 55→  for (const beam of floor.beams || []) {
 56→    const renderData = getBeamRenderData(beam, floor.columns || []);
 57→    if (renderData?.outline) points.push(...renderData.outline);
 58→  }
 59→  for (const stair of floor.stairs || []) {
 60→    const renderData = getStairRenderData(stair);
 61→    if (renderData?.outline) points.push(...renderData.outline);
 62→  }
 63→  for (const landing of floor.landings || []) {
 64→    points.push(...landingOutline(landing));
 65→  }
 66→  for (const column of floor.columns || []) {
 67→    points.push(...columnOutline(column));
 68→  }
 69→  for (const slab of (floor.slabs || [])) {
 70→    const rd = getSlabRenderData(slab);
 71→    if (rd?.boundaryPoints) points.push(...rd.boundaryPoints);
 72→  }
 73→  for (const sc of (floor.sectionCuts || [])) {
 74→    points.push(sc.startPoint, sc.endPoint);
 75→    const renderData = getSectionCutRenderData(sc);
 76→    if (renderData?.arrow) {
 77→      points.push(renderData.arrow.shaftStart, renderData.arrow.shaftEnd, renderData.arrow.headA, renderData.arrow.headB);
 78→    }
 79→  }
 80→
 81→  for (const door of floor.doors || []) {
 82→    const wall = (floor.walls || []).find((entry) => entry.id === door.wallId);
 83→    if (!wall) continue;
 84→    const outline = doorOutlineOnWall(wall, door);
 85→    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
 86→  }
 87→
 88→  for (const windowItem of floor.windows || []) {
 89→    const wall = (floor.walls || []).find((entry) => entry.id === windowItem.wallId);
 90→    if (!wall) continue;
 91→    const outline = windowOutlineOnWall(wall, windowItem);
 92→    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
 93→  }
 94→
 95→  for (const fixture of floor.fixtures || []) {
 96→    points.push(...fixtureOutline(fixture));
 97→  }
 98→
 99→  return points;
100→}
